text:
1. Simple bubble map (point data)
Points sized by a numeric value. The simplest useful map.
&lt;!DOCTYPE html&gt;
&lt;html lang="en"&gt;
&lt;head&gt;
    &lt;meta charset="UTF-8"&gt;
    &lt;title&gt;Bubble Map&lt;/title&gt;
    &lt;style&gt;
        html, body { width: 100%; height: 100%; margin: 0; overflow: hidden; }
        #map { width: 100%; height: 100%; }
    &lt;/style&gt;
    &lt;script src="https://cdn.jsdelivr.net/gh/gjrichter/ixmaps-flat@1/ixmaps.js"&gt;&lt;/script&gt;
&lt;/head&gt;
&lt;body&gt;
    &lt;div id="map"&gt;&lt;/div&gt;
    &lt;script&gt;
        const DATA = [
            { city: "Rome",    lat: 41.90, lon: 12.50, pop: 2873000 },
            { city: "Milan",   lat: 45.46, lon: 9.19,  pop: 1372000 },
            { city: "Naples",  lat: 40.85, lon: 14.27, pop:  966000 },
            { city: "Turin",   lat: 45.07, lon: 7.69,  pop:  875000 },
            { city: "Palermo", lat: 38.12, lon: 13.36, pop:  657000 }
        ];

        const myMap = ixmaps.Map("map", {
            mapType: "VT_TONER_LITE",
            mode:    "info",
            legend:  "closed",
            tools:   true
        })
        .view({ center: { lat: 42.5, lng: 12.5 }, zoom: 6 })
        .options({ basemapopacity: 0.6, flushChartDraw: 1000000 });

        myMap.layer("cities")
            .data({ obj: DATA, type: "json" })
            .binding({ geo: "lat|lon", value: "pop", title: "city" })
            .type("CHART|BUBBLE|SIZE|VALUES")
            .style({
                colorscheme:     ["#0066cc"],
                fillopacity:     0.7,
                normalsizevalue: "3000000",
                showdata:        "true"
            })
            .meta({ tooltip: "&lt;b&gt;{{city}}&lt;/b&gt;&lt;br&gt;Population: {{pop}}" })
            .title("Population")
            .define();
    &lt;/script&gt;
&lt;/body&gt;
&lt;/html&gt;

3. World choropleth (countries)
Colour world countries by a CSV value. The overlay layer reuses the geometry base’s name.
const myMap = ixmaps.Map("map", {
    mapType: "CartoDB - Positron",
    mode:    "info",
    legend:  "open"
})
.view({ center: { lat: 20, lng: 0 }, zoom: 2 })
.options({ basemapopacity: 0.5, flushChartDraw: 1000000 });

// 1 — geometry base
myMap.layer("countries")
    .data({
        url:  "https://gisco-services.ec.europa.eu/distribution/v2/countries/topojson/CNTR_RG_60M_2020_4326.json",
        type: "topojson"
    })
    .binding({ geo: "geometry", id: "CNTR_ID", title: "NAME_ENGL" })
    .type("FEATURE")
    .style({
        colorscheme: ["#ddd"],
        fillopacity: 0.3,
        linecolor:   "#aaa",
        linewidth:   0.4,
        showdata:    "true"
    })
    .define();

// 2 — choropleth overlay (SAME name "countries")
myMap.layer("countries")
    .data({ url: "https://example.com/gdp.csv", type: "csv" })
    .binding({ lookup: "iso2", value: "gdp_per_capita" })
    .type("CHOROPLETH|QUANTILE")
    .style({
        colorscheme: ["#ffffcc","#c7e9b4","#41b6c4","#2c7fb8","#253494"],
        fillopacity: 0.8,
        showdata:    "true"
    })
    .meta({ tooltip: "&lt;b&gt;{{NAME_ENGL}}&lt;/b&gt;&lt;br&gt;GDP per capita: {{gdp_per_capita}}" })
    .title("GDP per capita")
    .define();

4. Italy municipalities (choropleth + join)
Join ISTAT CSV data to municipality polygons. Note the pinned geometry URL for 2024-compatible codes.
const GEO_URL =
    "https://raw.githubusercontent.com/gjrichter/geo/0153a0e14da5dae877b8c94d6deb11f210d4660a/italy/boundaries/italy_istat_municipalities_4326_500m.topojson";

const myMap = ixmaps.Map("map", {
    mapType: "VT_TONER_LITE",
    mode:    "info",
    legend:  "closed"
})
.view({ center: { lat: 42.5, lng: 12.5 }, zoom: 6 })
.options({
    basemapopacity: 0.4,
    flushChartDraw: 1000000,
    flushPaintShape: 1000000   // required for ~8000 polygons
});

myMap.layer("comuni")
    .data({ url: GEO_URL, type: "topojson" })
    .binding({ geo: "geometry", id: "com_istat_code_num", title: "name" })
    .type("FEATURE")
    .style({
        colorscheme: ["#ccc"],
        fillopacity: 0.2,
        linecolor:   "#888",
        linewidth:   0.2,
        showdata:    "true"
    })
    .define();

myMap.layer("comuni")
    .data({ url: "https://example.com/istat_data.csv", type: "csv" })
    .binding({ lookup: "istat_code", value: "value" })
    .type("CHOROPLETH|QUANTILE")
    .style({
        colorscheme: ["#fff7fb","#ece2f0","#a6bddb","#1c9099","#016450"],
        fillopacity: 0.85,
        showdata:    "true"
    })
    .meta({ tooltip: "&lt;b&gt;{{name}}&lt;/b&gt;&lt;br&gt;{{value}}" })
    .title("Value by municipality")
    .define();

5. Swappable themes (remove-then-define)
Switch between multiple visualisations of the same geometry without stacking layers.
let ACTIVE_THEME = null;

function setTheme(id, type, styleOverride) {
    const themeName = "theme-" + id;
    const prev = ACTIVE_THEME;

    myMap.then(api =&gt; {
        if (prev) { try { api.removeTheme(prev); } catch(e) {} }

        myMap.layer("regions")               // SAME name as FEATURE base
            .data({ obj: DATA, type: "json", cache: "true" })
            .binding({ lookup: "code", value: id })
            .type(type)
            .style(Object.assign({ showdata: "true" }, styleOverride))
            .meta({ name: themeName, tooltip: "{{name}}: {{" + id + "}}" })
            .define();

        ACTIVE_THEME = themeName;
    });
}

// Switch between indicators:
setTheme("population", "CHOROPLETH|QUANTILE",
    { colorscheme: ["#ffffcc","#253494"], fillopacity: 0.8 });

setTheme("income", "CHOROPLETH|NATURAL",
    { colorscheme: ["#fff5f0","#a50f15"], fillopacity: 0.8 });

6. Animated time series
Show one year at a time, stepping through with a slider.
const yearData = {
    "2020": [...],
    "2021": [...],
    "2022": [...],
    "2023": [...]
};

let ACTIVE = null;

function showYear(year) {
    const themeName = "year-" + year;
    const prev = ACTIVE;

    myMap.then(api =&gt; {
        if (prev) { try { api.removeTheme(prev); } catch(e) {} }

        myMap.layer("countries")
            .data({ obj: yearData[year], type: "json" })
            .binding({ geo: "lat|lon", value: "metric", title: "name" })
            .type("CHART|BUBBLE|SIZE|VALUES")
            .style({
                colorscheme:     ["#0066cc"],
                fillopacity:     0.7,
                normalsizevalue: "1000000",
                showdata:        "true"
            })
            .meta({ name: themeName, tooltip: "{{name}}: {{metric}}" })
            .define();

        ACTIVE = themeName;
    });
}

// HTML: &lt;input type="range" min="2020" max="2023" oninput="showYear(this.value)"&gt;
showYear("2020");

7. Flow map (origin → destination)
Arrows from source to destination, with optional animation.
const flows = [
    { from_name: "Rome",  from_lat: 41.90, from_lon: 12.50,
      to_lat: 48.86, to_lon: 2.35, volume: 5000 },
    { from_name: "Milan", from_lat: 45.46, from_lon: 9.19,
      to_lat: 51.51, to_lon: -0.13, volume: 8000 }
];

myMap.layer("flows")
    .data({ obj: flows, type: "json" })
    .binding({
        geo:   "from_lat|from_lon",
        value: "volume",
        title: "from_name",
        geo2:  "to_lat|to_lon"
    })
    .type("CHART|VECTOR|BEZIER|POINTER|DASH")
    .style({
        colorscheme: ["#0066cc"],
        fillopacity: 0.7,
        linewidth:   2,
        showdata:    "true"
    })
    .meta({ tooltip: "{{from_name}} → volume: {{volume}}" })
    .define();

8. Sparklines (time-series curves per location)
A sparkline curve at each data point showing multi-year trends.
const DATA = [
    { city: "Rome",  lat: 41.90, lon: 12.50, v2020: 100, v2021: 108, v2022: 115, v2023: 122 },
    { city: "Milan", lat: 45.46, lon: 9.19,  v2020: 90,  v2021: 95,  v2022: 99,  v2023: 105 }
];

myMap.layer("trends")
    .data({ obj: DATA, type: "json" })
    .binding({ geo: "lat|lon", value: "v2020|v2021|v2022|v2023", title: "city" })
    .type("CHART|SYMBOL|PLOT|LINES|AREA|LASTARROW|NOCLIP|GRIDSIZE|FIXSIZE")
    .style({
        gridwidth:       "100px",
        normalsizevalue: "30",
        markersize:      2,
        colorscheme:     ["#00e5ff"],
        fillopacity:     0.5,
        showdata:        "true"
    })
    .meta({ tooltip: "{{city}}&lt;br&gt;{{theme.item.chart}}" })
    .define();

10. Equal Earth world map (projection)
A world map using the Equal Earth projection — no tile layer, SVG only.
const myMap = ixmaps.Map("map", {
    mapType:       "#0a1929",       // dark ocean background
    mapProjection: "equalearth",
    mode:          "info",
    legend:        "closed"
})
.view([0, 0], 1)                   // array syntax required for projections
.options({ basemapopacity: 0, flushChartDraw: 1000000 });

myMap.layer("countries")
    .data({
        url:  "https://gisco-services.ec.europa.eu/distribution/v2/countries/topojson/CNTR_RG_60M_2020_4326.json",
        type: "topojson"
    })
    .binding({ geo: "geometry", id: "CNTR_ID", title: "NAME_ENGL" })
    .type("FEATURE")
    .style({
        colorscheme: ["#1a3a5c"],
        fillopacity: 0.9,
        linecolor:   "#4a7fc1",
        linewidth:   0.4,
        showdata:    "true"
    })
    .define();

// Add data overlay with external CSV
myMap.layer("countries")
    .data({ url: "https://example.com/world_data.csv", type: "csv" })
    .binding({ lookup: "iso2", value: "value" })
    .type("CHOROPLETH|QUANTILE")
    .style({
        colorscheme: ["#08306b","#2171b5","#6baed6","#bdd7e7","#eff3ff"],
        fillopacity: 0.85,
        showdata:    "true"
    })
    .meta({ tooltip: "&lt;b&gt;{{NAME_ENGL}}&lt;/b&gt;: {{value}}" })
    .define();

11. External data via jsDelivr CDN
Best practice for production maps — keep data outside the HTML file.
// Data hosted at github.com/your-user/your-repo/data/cities.csv
// CDN URL pattern: cdn.jsdelivr.net/gh/&lt;user&gt;/&lt;repo&gt;@&lt;branch&gt;/&lt;path&gt;

myMap.layer("cities")
    .data({
        url:  "https://cdn.jsdelivr.net/gh/gjrichter/data@main/cities/italy.csv",
        type: "csv"
    })
    .binding({ geo: "lat|lon", value: "population", title: "name" })
    .type("CHART|BUBBLE|SIZE|VALUES")
    .style({
        colorscheme:     ["#0066cc"],
        fillopacity:     0.7,
        normalsizevalue: "3000000",
        showdata:        "true"
    })
    .meta({ tooltip: "&lt;b&gt;{{name}}&lt;/b&gt;&lt;br&gt;Population: {{population}}" })
    .define();
Benefits: small HTML (no inline data), separate data versioning, free CDN, CORS-enabled.

The plugin principle
The API rests on a strict division of labour:
iXMaps does everything around the drawing — loading and filtering the data, aggregating values, positioning the chart (lat/lon anchor, geometry centroid with RELOCATE, or grid cell), computing its size through the regular sizing system (normalsizevalue, sizepow, zoom scaling), resolving the color class from colorscheme, and integrating legend and tooltips.
The plugin does one thing: draw its SVG code into the SVG target that iXMaps hands it (args.target, a prepared &lt;g&gt; group). It reads the precomputed value, size and color from args and produces shapes — nothing else. That is why plugin code stays small: each of the shipped plugins is essentially one SVG path plus an optional label.

SVG library — your choice
The three shipped plugins draw with D3 (v3), which is comfortable for SVG generation — but D3 is not mandatory. The plugin contract is only “put SVG into args.target”; any technique works, including native DOM:
ixmaps.squareChart = function (SVGDocument, args) {
    var size = args.size || 50;
    var rect = SVGDocument.createElementNS("http://www.w3.org/2000/svg", "rect");
    rect.setAttribute("x", -size / 2);
    rect.setAttribute("y", -size / 2);
    rect.setAttribute("width",  size);
    rect.setAttribute("height", size);
    rect.setAttribute("fill", args.theme.colorScheme[args.class]);
    args.target.appendChild(rect);
};
The D3 &lt;script&gt; include shown below is required by the three shipped plugins; a plugin of your own only needs whatever it uses itself.

How custom chart functions work
You write a JavaScript function, attach it to the ixmaps namespace, then reference it by name in .style({ userdraw: "functionName" }). iXMaps calls your function once per rendered feature, passing the SVG context and data.
Function signature:
ixmaps.myChart = function(SVGDocument, args) {
    // args properties:
    //   args.target     — the SVG group element to draw into
    //   args.value      — the primary data value for this feature
    //   args.values     — array of all values (for multi-value bindings)
    //   args.theme      — theme object (contains style, color scheme, etc.)
    //   args.item       — the raw data item/row
    //   args.dbRecord   — the full underlying database record
    //   args.size       — this item's computed radius/size
    //   args.maxSize    — the theme's maximum radius/size
    //   args.color      — the resolved fill color
    //   args.textcolor  — the resolved text color
    //   args.ccolor     — chart-derived colors (from the theme's color scheme)
    //   args.class      — color class index (maps to colorscheme)
    //   args.flag       — the raw type-string ("flag") of the theme
    //   args.mark       — an internal per-item marker value

    var svg = d3.select(args.target);
    // ... draw with D3 or SVG DOM methods ...

    return { x: 0, y: 0 };  // offset used to reposition the chart group — a falsy return counts as a draw error
};
Two optional companion functions, named by suffixing your userdraw name, run once before/after the whole per-feature loop rather than once per feature — useful for setup/teardown (e.g. building a shared &lt;defs&gt; block):
ixmaps.myChart_init   = function(SVGDocument, args) { /* args = { target, theme } — runs once before */ };
ixmaps.myChart_finish = function(SVGDocument, args) { /* args = { target, theme } — runs once after */ };






Warninguserdraw vs chartdraw



The current flat API uses userdraw as the style property name. Older iXMaps documentation and the legacy API used chartdraw — this name is no longer valid with the flat API.

Required scripts (shipped plugins)
For the three shipped plugins, D3 plus the script of each chart function you use are required in addition to ixmaps.js — a plugin of your own needs neither unless it draws with D3 itself:
&lt;script src="https://cdn.jsdelivr.net/gh/gjrichter/ixmaps-flat@1/ixmaps.js"&gt;&lt;/script&gt;
&lt;script src="https://d3js.org/d3.v3.min.js"&gt;&lt;/script&gt;
&lt;script src="https://cdn.jsdelivr.net/gh/gjrichter/ixmaps-flat@1/usercharts/d3/chart.js"&gt;&lt;/script&gt;       &lt;!-- pinnacleChart --&gt;
&lt;script src="https://cdn.jsdelivr.net/gh/gjrichter/ixmaps-flat@1/usercharts/d3/arrow_chart.js"&gt;&lt;/script&gt; &lt;!-- arrowChart --&gt;
&lt;script src="https://cdn.jsdelivr.net/gh/gjrichter/ixmaps-flat@1/usercharts/d3/lolli_chart.js"&gt;&lt;/script&gt; &lt;!-- lolliChart --&gt;
Script load order relative to ixmaps.js does not matter.

Enabling tooltips
The map’s mode option controls whether the feature layer responds to the mouse. It is not fixed at construction time — it can be changed at any point:
const myMap = ixmaps.Map("map", {
    mapType: "VT_TONER_LITE",
    mode:    "info"          // hover shows tooltips immediately
});

mode: "info" — the feature layer stays interactive. Hovering over an SVG object bound to a theme shows its tooltip right away.
mode: "pan" (the default) — the base map handles panning and zooming; the feature layer normally ignores the mouse. A single click briefly runs the same processing as "info" mode for that instant — if a themed feature is under the pointer, its tooltip appears — then the map switches back to "pan" automatically once the pointer moves on.

Change the mode at runtime with ixmaps.setMode("info" | "pan") (or ixmaps.toggleInputMode() to flip between the two), or let users switch it themselves via the built-in mode button — pass tools: true (or toolbutton: true) to the constructor to show it.
A plain FEATURE layer with no theme bound to it falls back to an auto-generated field list instead of a custom tooltip — a holdover from ixMaps’ original QGIS-tiled-SVG generator, which baked tooltips directly into the SVG.

Styling the tooltip
The tooltip is a regular HTML element with id tooltip — style it with CSS. On dark basemaps the default text color can be invisible:
#tooltip   { color: #e8eaf6 !important; }
#tooltip * { color: #e8eaf6 !important; }






NoteReserved element ids



iXMaps owns the element ids tooltip, loading-div and contextmenu. Never use them for your own page elements — see Troubleshooting.

Runtime theme changes
React to user input by changing live themes through myMap.then(). All of these require a name in the layer’s .meta():
Filter a theme:
myMap.then(api =&gt; {
    api.changeThemeStyle("cities", 'filter:WHERE pop &gt; 500000', "set");
    // and back:
    api.changeThemeStyle("cities", "filter", "remove");
});
Toggle a layer with a checkbox:
myMap.layer("overlay")
    .style({ /* ... */, visible: false })   // starts hidden
    .meta({ name: "overlay" })
    .define();
&lt;input type="checkbox"
       onchange="this.checked ? ixmaps.showTheme('overlay') : ixmaps.hideTheme('overlay')"&gt;
Swap the visualization (remove-then-define) — see Examples § Swappable themes for the full pattern.
For changeThemeStyle modes (set, remove, factor, set|silent) and the rest of the runtime API, see the API Reference.

scale — direct multiplier
The simplest lever: a bare multiplier applied after everything else. Per principle 4, keep it at 1 in layer definitions and size themes via normalsizevalue; use scale for runtime adjustments and for compensating visual effects:
.style({ scale: 0.32 })  // legitimate: offset the |GLOW halo's apparent size

// runtime — interactive size adjustment:
myMap.then(api =&gt; api.changeThemeStyle("layerName", "scale:0.9", "factor"));

dynamicScalePow — zoom rate
Controls how quickly symbols grow or shrink as the user zooms. The default is 3 (cubic root), which provides smooth transitions without extreme size changes.
Formula: DynamicScale = (1 / scaleRatio) ^ (1 / dynamicScalePow)
.options({
    objectscaling:   "dynamic",
    normalSizeScale: "8000000",
    dynamicScalePow: "3"    // default — cubic root, smooth transitions
    // dynamicScalePow: "1.8"  // more aggressive growth on zoom-in (dense datasets)
})
Higher values produce faster growth when zooming in. For dense point datasets where you want symbols to spread out noticeably on zoom, use "1.8". For sparse data where continuity matters more, keep the default "3".

Urban trees preset
A reliable starting point for street-level zoom (zoom 14–16) with species bubbles and |GLOW:
.options({
    objectscaling:   "dynamic",
    normalSizeScale: "5000"      // street scale
})
.style({
    normalsizevalue: "220",      // diameter in cm — controls relative sizing
    scale:           0.32,       // reduce glow halo size
    fillopacity:     0.8,
    showdata:        "true"
})
.type("CHART|BUBBLE|CATEGORICAL|GLOW")

Scale-dependent visibility
Hide a layer when the map is too zoomed out or too zoomed in:
.style({
    chartupper: "1:5000",   // hide when denominator &gt; 5000 (zoomed out)
    chartlower: "1:500"     // hide when denominator &lt; 500 (zoomed in)
})
Background boxes can also appear/disappear by scale:
.style({
    boxupper: "1:250000"    // box visible only at denominator ≤ 250 000
})

Runtime size adjustments
Change size interactively after the map loads:
// Set scale to 2x:
myMap.then(api =&gt; api.changeThemeStyle("layerName", "scale:2.0", "set"));

// Shrink by 10 %:
myMap.then(api =&gt; api.changeThemeStyle("layerName", "scale:0.9", "factor"));

// Grow grid cells by 10 %:
myMap.then(api =&gt; api.changeThemeStyle("layerName", "gridwidthpx:1.1", "factor"));

Step 1: The HTML skeleton
Create an HTML file and include the iXMaps library from the CDN:
&lt;!DOCTYPE html&gt;
&lt;html lang="en"&gt;
&lt;head&gt;
    &lt;meta charset="UTF-8"&gt;
    &lt;meta name="viewport" content="width=device-width, initial-scale=1.0"&gt;
    &lt;title&gt;My First ixMap&lt;/title&gt;
    &lt;style&gt;
        html, body { width: 100%; height: 100%; margin: 0; overflow: hidden; }
        #map { width: 100%; height: 100%; }
    &lt;/style&gt;
    &lt;!-- iXMaps library — single script, no other dependencies needed --&gt;
    &lt;script src="https://cdn.jsdelivr.net/gh/gjrichter/ixmaps-flat@1/ixmaps.js"&gt;&lt;/script&gt;
&lt;/head&gt;
&lt;body&gt;
    &lt;div id="map"&gt;&lt;/div&gt;
    &lt;script&gt;
        // your map code goes here
    &lt;/script&gt;
&lt;/body&gt;
&lt;/html&gt;






ImportantCSS rule required



Never use width: 100vw; height: 100vh on the map &lt;div&gt;. When a scrollbar appears, vw/vh exceed the viewport and trigger a feedback loop. Always use the width/height: 100% pattern shown above.








NoteNo extra scripts needed



data.js is loaded automatically when ixmaps.Map() initializes — Data.* functions are available in any code that runs after that (layer callbacks, .then(), event handlers). Only if you need Data before creating the map do you add its own &lt;script&gt; tag — see Data Preprocessing.

Step 2: Create a map
The entry point is ixmaps.Map(). Always assign the result to a const — discarding the return value silently breaks all subsequent calls.
const myMap = ixmaps.Map("map", {
    mapType: "VT_TONER_LITE",  // basemap style
    mode:    "info",            // "info" = show tooltips on hover
    legend:  "closed",          // legend panel starts collapsed
    tools:   true               // show toolbar (zoom, search)
})
.view({ center: { lat: 42.5, lng: 12.5 }, zoom: 6 })
.options({
    basemapopacity: 0.6,
    flushChartDraw:  1000000    // instant rendering (no animation)
});
Open this in a browser — you should see a clean toner basemap centred on Italy.

Complete working example
&lt;!DOCTYPE html&gt;
&lt;html lang="en"&gt;
&lt;head&gt;
    &lt;meta charset="UTF-8"&gt;
    &lt;meta name="viewport" content="width=device-width, initial-scale=1.0"&gt;
    &lt;title&gt;Italian Cities&lt;/title&gt;
    &lt;style&gt;
        html, body { width: 100%; height: 100%; margin: 0; overflow: hidden; }
        #map { width: 100%; height: 100%; }
    &lt;/style&gt;
    &lt;script src="https://cdn.jsdelivr.net/gh/gjrichter/ixmaps-flat@1/ixmaps.js"&gt;&lt;/script&gt;
&lt;/head&gt;
&lt;body&gt;
    &lt;div id="map"&gt;&lt;/div&gt;
    &lt;script&gt;
        const cities = [
            { name: "Rome",    lat: 41.90, lon: 12.50, pop: 2873000 },
            { name: "Milan",   lat: 45.46, lon: 9.19,  pop: 1372000 },
            { name: "Naples",  lat: 40.85, lon: 14.27, pop:  966000 },
            { name: "Turin",   lat: 45.07, lon: 7.69,  pop:  875000 },
            { name: "Palermo", lat: 38.12, lon: 13.36, pop:  657000 }
        ];

        const myMap = ixmaps.Map("map", {
            mapType: "VT_TONER_LITE",
            mode:    "info",
            legend:  "closed",
            tools:   true
        })
        .view({ center: { lat: 42.5, lng: 12.5 }, zoom: 6 })
        .options({ basemapopacity: 0.6, flushChartDraw: 1000000 });

        myMap.layer("cities")
            .data({ obj: cities, type: "json" })
            .binding({ geo: "lat|lon", value: "pop", title: "name" })
            .type("CHART|BUBBLE|SIZE|VALUES")
            .style({
                colorscheme:     ["#0066cc"],
                fillopacity:     0.7,
                normalsizevalue: "3000000",
                showdata:        "true"
            })
            .meta({ tooltip: "&lt;b&gt;{{name}}&lt;/b&gt;&lt;br&gt;Population: {{pop}}" })
            .title("Italian Cities")
            .define();
    &lt;/script&gt;
&lt;/body&gt;
&lt;/html&gt;
Save the file and open it in any modern browser. No web server needed for inline data like this.






